.date-range {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  margin: 0;
  padding: 1rem;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 12px;
}
.date-range-legend {
  padding: 0 0.4rem;
  font-size: 0.7em;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--color-text-muted);
}
.date-range-presets { display: flex; flex-wrap: wrap; gap: 0.4rem; }
.date-range-preset {
  padding: 0.3rem 0.7rem;
  font: inherit;
  font-size: 0.85em;
  background: rgba(0, 0, 0, 0.03);
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 999px;
  cursor: pointer;
}
.date-range-preset:hover { background: rgba(0, 0, 0, 0.06); }
.date-range-fields { display: flex; align-items: flex-end; gap: 0.75rem; }
.date-range-field { display: flex; flex-direction: column; gap: 0.25rem; }
.date-range-label { font-size: 0.8em; color: var(--color-text-muted); }
.date-range-input {
  padding: 0.4rem 0.6rem;
  font: inherit;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 8px;
}
.date-range-dash { align-self: center; color: var(--color-text-muted); }
.date-range-error { margin: 0; color: #dc2626; font-size: 0.85em; }

/* date-range.js (#860) — progressive enhancement for the from/to date-range
 * field. Baseline markup is two native <input type="date">s; the native pickers
 * and locale-aware display come free from the platform. This layers: quick-range
 * presets, a from <= to clamp (mirrored onto each input's min/max so the native
 * picker enforces it too), and a single normalized "daterange:change" event.
 */
(function () {
  'use strict';
  var iso = function (d) { return d.toISOString().slice(0, 10); };
  Array.prototype.forEach.call(document.querySelectorAll('[data-date-range]'), function (root) {
    var from = root.querySelector('[data-range-from]');
    var to = root.querySelector('[data-range-to]');
    var error = root.querySelector('[data-range-error]');
    if (!from || !to) return;
    if (root.dataset.min) { from.min = root.dataset.min; to.min = root.dataset.min; }
    if (root.dataset.max) { from.max = root.dataset.max; to.max = root.dataset.max; }

    var validate = function () {
      var bad = from.value && to.value && from.value > to.value;
      if (error) error.hidden = !bad;
      to.setCustomValidity(bad ? 'End date is before start date' : '');
      return !bad;
    };
    var emit = function () {
      if (!validate()) return;
      // Clamp the native pickers to the chosen bounds.
      to.min = from.value || (root.dataset.min || '');
      from.max = to.value || (root.dataset.max || '');
      root.dispatchEvent(new CustomEvent('daterange:change', { bubbles: true, detail: { from: from.value, to: to.value } }));
    };

    from.addEventListener('change', emit);
    to.addEventListener('change', emit);

    root.addEventListener('click', function (e) {
      var btn = e.target.closest('[data-range-preset]');
      if (!btn) return;
      var spec = btn.dataset.rangePreset;
      var end = new Date();
      var start = new Date();
      if (spec === 'month') { start = new Date(end.getFullYear(), end.getMonth(), 1); }
      else { start.setDate(end.getDate() - (parseInt(spec, 10) - 1)); }
      from.value = iso(start);
      to.value = iso(end);
      emit();
    });
  });
})();
